import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';
import { Cart, Order, OrderStatus, Product, ServiceSetting, User } from './models';

/**
 * Storefront API client. Typed against models.ts and the surface contract.
 * The mockup pages render local signal mock data; the service_agent stage
 * wires these methods into the page components via ngOnInit().
 */
@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly base = environment.apiUrl;

  constructor(private http: HttpClient) {}

  // ---- Users ----
  me(): Observable<User> {
    return this.http.get<User>(`${this.base}/users/me`);
  }

  // ---- Products (public reads, admin writes) ----
  listProducts(q?: string): Observable<Product[]> {
    let params = new HttpParams();
    if (q) params = params.set('q', q);
    return this.http.get<Product[]>(`${this.base}/products`, { params });
  }
  getProduct(id: string): Observable<Product> {
    return this.http.get<Product>(`${this.base}/products/${id}`);
  }
  createProduct(body: Partial<Product>): Observable<Product> {
    return this.http.post<Product>(`${this.base}/products`, body);
  }
  updateProduct(id: string, body: Partial<Product>): Observable<Product> {
    return this.http.patch<Product>(`${this.base}/products/${id}`, body);
  }
  deleteProduct(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/products/${id}`);
  }

  // ---- Cart (any logged-in user) ----
  getCart(): Observable<Cart> {
    return this.http.get<Cart>(`${this.base}/cart`);
  }
  addToCart(productId: string, qty: number): Observable<Cart> {
    return this.http.post<Cart>(`${this.base}/cart/items`, { productId, qty });
  }
  updateCartItem(productId: string, qty: number): Observable<Cart> {
    return this.http.patch<Cart>(`${this.base}/cart/items/${productId}`, { qty });
  }
  removeCartItem(productId: string): Observable<Cart> {
    return this.http.delete<Cart>(`${this.base}/cart/items/${productId}`);
  }

  // ---- Orders (checkout + history) ----
  placeOrder(body: { shipName: string; shipAddress: string }): Observable<Order> {
    return this.http.post<Order>(`${this.base}/orders`, body);
  }
  myOrders(): Observable<Order[]> {
    return this.http.get<Order[]>(`${this.base}/orders/mine`);
  }
  getOrder(id: string): Observable<Order> {
    return this.http.get<Order>(`${this.base}/orders/${id}`);
  }
  allOrders(): Observable<Order[]> {
    return this.http.get<Order[]>(`${this.base}/orders`);
  }
  setOrderStatus(id: string, status: OrderStatus): Observable<Order> {
    return this.http.patch<Order>(`${this.base}/orders/${id}/status`, { status });
  }

  // ---- Admin settings (provisioned service credentials) ----
  getSettings(): Observable<ServiceSetting[]> {
    return this.http.get<ServiceSetting[]>(`${this.base}/admin/settings`);
  }
  updateSettings(pairs: Record<string, string>): Observable<ServiceSetting[]> {
    return this.http.patch<ServiceSetting[]>(`${this.base}/admin/settings`, pairs);
  }
}
